const fs = require('fs');
const path = require('path');

const FILE = path.join(__dirname, 'index.html');
if (!fs.existsSync(FILE)) { console.error('Not found: index.html'); process.exit(1); }

let html = fs.readFileSync(FILE, 'utf8');
let count = 0;

// OST Composer (has badge-hot)
var oldOST = `  <div class="tool-card">
    <div class="badge-hot">HOT</div>
    <div class="tc-icon">🎵</div>
    <div class="tc-name">OST Composer</div>
    <div class="tc-desc">Adaptive game music, any genre</div>
  </div>`;
var newOST = `  <div class="tool-card" style="padding:0;overflow:hidden;position:relative;min-height:140px">
    <img src="data:image/avif;base64," alt="OST Composer" style="width:100%;height:100%;object-fit:cover;border-radius:8px;display:block"/>
    <div style="position:absolute;top:8px;left:8px"><div class="badge-hot">HOT</div></div>
    <div style="position:absolute;bottom:0;left:0;right:0;padding:10px 12px;background:linear-gradient(transparent,rgba(0,0,0,.9))">
      <div class="tc-name" style="font-size:13px">OST Composer</div>
      <div class="tc-desc" style="font-size:11px">Adaptive game music, any genre</div>
    </div>
  </div>`;

if (html.includes(oldOST)) {
  html = html.replace(oldOST, newOST);
  count++;
  console.log('✅  OST Composer wired');
} else {
  console.log('⚠️   OST Composer not found');
}

// NPC Brain (has badge-new)
var oldNPC = `  <div class="tool-card">
    <div class="badge-new">NEW</div>
    <div class="tc-icon">🤖</div>
    <div class="tc-name">NPC Brain</div>
    <div class="tc-desc">Inworld AI — living, reactive characters</div>
  </div>`;
var newNPC = `  <div class="tool-card" style="padding:0;overflow:hidden;position:relative;min-height:140px">
    <img src="data:image/jpeg;base64," alt="NPC Brain" style="width:100%;height:100%;object-fit:cover;border-radius:8px;display:block"/>
    <div style="position:absolute;top:8px;left:8px"><div class="badge-new">NEW</div></div>
    <div style="position:absolute;bottom:0;left:0;right:0;padding:10px 12px;background:linear-gradient(transparent,rgba(0,0,0,.9))">
      <div class="tc-name" style="font-size:13px">NPC Brain</div>
      <div class="tc-desc" style="font-size:11px">Inworld AI — living, reactive characters</div>
    </div>
  </div>`;

if (html.includes(oldNPC)) {
  html = html.replace(oldNPC, newNPC);
  count++;
  console.log('✅  NPC Brain wired');
} else {
  console.log('⚠️   NPC Brain not found');
}

fs.writeFileSync(FILE, html, 'utf8');
console.log('\n🎉  Done — ' + count + '/2 remaining cards wired');
